from vex import verify
from llama_index.core import VectorStoreIndex

index = VectorStoreIndex.from_documents(documents)
query_engine = index.as_query_engine()

@verify(guards=["source-verification", "claim-accuracy"])
def research_query(question: str):
    raw_response = query_engine.query(question)
    return {
        "answer": str(raw_response),
        "sources": [node.metadata for node in raw_response.source_nodes]
    }

result = research_query("Latest AI research trends?")
