from vex import verify
import datetime
from llama_index.core import SimpleWebPageReader

@verify(guards=["recency-check", "bias-detection"], max_age_days=7)
def web_research_agent(urls: list, query: str):
    reader = SimpleWebPageReader(html_to_text=True)
    docs = reader.load_data(urls)
    index = VectorStoreIndex.from_documents(docs)
    response = index.as_query_engine().query(query)

    return {
        "summary": str(response),
        "publish_dates": [doc.metadata.get('publish_date') for doc in docs],
        "sources": urls
    }

result = web_research_agent([
    "https://techcrunch.com/ai",
    "https://venturebeat.com/ai"
], "AI investment trends")
print(result)
